use bevy::prelude::*;

/// All the tunables of the cloud skybox demo, driven by the egui sliders.
#[derive(Resource, Clone, Debug, PartialEq)]
pub struct CloudSkySettings {
    /// Hour of the day, 0..24. Sunrise ~6, noon 13, sunset ~19.
    pub time_of_day: f32,
    /// Wind scroll speed of the cloud layers (uv units / second).
    pub wind_speed: f32,
    /// Wind direction in degrees (0 = +X, 90 = +Z).
    pub wind_direction_deg: f32,
    /// Global scale multiplier for the cloud noise.
    pub cloud_scale: f32,

    /// Coverage of the puffy low-altitude cumulus layer (0..1).
    pub cumulus_amount: f32,
    /// FBM octaves for the cumulus layer (1..8).
    pub cumulus_detail: f32,

    /// Coverage of the wispy high-altitude cirrus veil (0..1).
    pub cirrus_amount: f32,
    /// FBM octaves for the cirrus layer (1..8).
    pub cirrus_detail: f32,

    /// Coverage of the dark low storm layer (0..1).
    pub storm_amount: f32,
    /// FBM octaves for the storm layer (1..8).
    pub storm_detail: f32,

    /// Rain streak intensity (0..1).
    pub rain_intensity: f32,
    /// Snow flake intensity (0..1).
    pub snow_intensity: f32,

    /// Opacity of the cloud shadows projected on the ground (0..1).
    pub cloud_shadow_intensity: f32,
}

impl Default for CloudSkySettings {
    fn default() -> Self {
        Self {
            time_of_day: 14.5,
            wind_speed: 0.02,
            wind_direction_deg: 45.0,
            cloud_scale: 0.23,
            cumulus_amount: 0.55,
            cumulus_detail: 7.0,
            cirrus_amount: 0.45,
            cirrus_detail: 7.0,
            storm_amount: 0.5,
            storm_detail: 7.6,
            rain_intensity: 0.0,
            snow_intensity: 0.0,
            cloud_shadow_intensity: 0.35,
        }
    }
}

impl CloudSkySettings {
    /// Direction from a point on the ground toward the sun, plus a 0..1
    /// "day factor" (0 = deep night, 1 = full day), derived from `time_of_day`.
    pub fn sun_dir_and_day_factor(&self) -> (Vec3, f32) {
        let t = (self.time_of_day - 6.0) / 12.0 * std::f32::consts::PI;
        let elevation_sin = t.sin();
        // Azimuth sweeps east -> west over the day.
        let azimuth = (self.time_of_day - 12.0) / 12.0 * std::f32::consts::PI;
        let cos_el = elevation_sin.max(0.02).sqrt(); // cheap flattening near horizon
        let sun_dir = Vec3::new(
            azimuth.sin() * cos_el,
            elevation_sin.max(-1.0),
            -azimuth.cos() * cos_el,
        )
        .normalize_or_zero();
        let day_factor = smoothstep(-0.05, 0.15, elevation_sin);
        (sun_dir, day_factor)
    }

    /// Wind scroll vector in uv units / second.
    pub fn wind_vec(&self) -> Vec2 {
        let rad = self.wind_direction_deg.to_radians();
        Vec2::new(rad.cos(), rad.sin()) * self.wind_speed
    }
}

fn smoothstep(edge0: f32, edge1: f32, x: f32) -> f32 {
    let t = ((x - edge0) / (edge1 - edge0)).clamp(0.0, 1.0);
    t * t * (3.0 - 2.0 * t)
}

use bevy::prelude::*;
use bevy::render::render_resource::{AsBindGroup, ShaderType};
use bevy::shader::ShaderRef;

/// Uniforms shared by the sky dome and the precipitation overlay.
///
/// Everything is packed into `Vec4`s so the struct stays 16-byte aligned
/// and WebGL2-friendly.
#[derive(Clone, Copy, ShaderType, Debug)]
pub struct SkyParamsUniform {
    /// xyz = direction toward the sun, w = day factor (0 night .. 1 day).
    pub sun_dir: Vec4,
    /// x = cumulus amount, y = cirrus amount, z = storm amount, w = overcast.
    pub amounts: Vec4,
    /// x = cumulus octaves, y = cirrus octaves, z = storm octaves, w = cloud scale.
    pub detail: Vec4,
    /// x = wind uv.x, y = wind uv.y (per second), z = rain intensity, w = snow intensity.
    pub wind: Vec4,
}

// Sky dome material: blue gradient + sun + 3 cloud layers, fully procedural.
#[derive(Asset, TypePath, AsBindGroup, Clone, Debug)]
pub struct SkyDomeMaterial {
    #[uniform(0)]
    pub params: SkyParamsUniform,
}

impl Material for SkyDomeMaterial {
    fn fragment_shader() -> ShaderRef {
        "embedded://demo_resolution_selector_web_bevy/plugins/cloud_sky/skybox_clouds.wgsl".into()
    }
    fn vertex_shader() -> ShaderRef {
        "embedded://demo_resolution_selector_web_bevy/plugins/cloud_sky/skybox_clouds.wgsl".into()
    }
    fn alpha_mode(&self) -> AlphaMode {
        // Opaque on purpose: the dome sits in the opaque phase (with depth
        // write off) so transparent overlays — rain/snow, ground shadow —
        // always draw on top of the sky. With Blend, the transparent phase
        // would sort the camera-centered dome last and it would cover them.
        AlphaMode::Opaque
    }
    fn enable_prepass() -> bool {
        false
    }
    fn enable_shadows() -> bool {
        false
    }
    fn specialize(
        _pipeline: &bevy::pbr::MaterialPipeline,
        descriptor: &mut bevy::render::render_resource::RenderPipelineDescriptor,
        _layout: &bevy::render::mesh::MeshVertexBufferLayoutRef,
        _key: bevy::pbr::MaterialPipelineKey<Self>,
    ) -> Result<(), bevy::render::render_resource::SpecializedMeshPipelineError> {
        descriptor.primitive.cull_mode = None;
        // Keep the depth test (ground occludes the sky) but don't write:
        // the dome behaves like geometry at infinity.
        if let Some(depth) = descriptor.depth_stencil.as_mut() {
            depth.depth_write_enabled = Some(false);
        }
        Ok(())
    }
}

// Camera-following overlay quad for rain/snow. No depth testing so the
// precipitation also draws in front of the world geometry.
#[derive(Asset, TypePath, AsBindGroup, Clone, Debug)]
pub struct PrecipOverlayMaterial {
    #[uniform(0)]
    pub params: SkyParamsUniform,
}

impl Material for PrecipOverlayMaterial {
    fn fragment_shader() -> ShaderRef {
        "embedded://demo_resolution_selector_web_bevy/plugins/cloud_sky/precip_overlay.wgsl".into()
    }
    fn vertex_shader() -> ShaderRef {
        "embedded://demo_resolution_selector_web_bevy/plugins/cloud_sky/precip_overlay.wgsl".into()
    }
    fn alpha_mode(&self) -> AlphaMode {
        AlphaMode::Blend
    }
    fn enable_prepass() -> bool {
        false
    }
    fn enable_shadows() -> bool {
        false
    }
    fn specialize(
        _pipeline: &bevy::pbr::MaterialPipeline,
        descriptor: &mut bevy::render::render_resource::RenderPipelineDescriptor,
        _layout: &bevy::render::mesh::MeshVertexBufferLayoutRef,
        _key: bevy::pbr::MaterialPipelineKey<Self>,
    ) -> Result<(), bevy::render::render_resource::SpecializedMeshPipelineError> {
        descriptor.primitive.cull_mode = None;
        // Keep the depth attachment format (the render pass has one) but
        // never test or write depth: precipitation draws over the world.
        if let Some(depth) = descriptor.depth_stencil.as_mut() {
            depth.depth_write_enabled = Some(false);
            depth.depth_compare = Some(bevy::render::render_resource::CompareFunction::Always);
        }
        Ok(())
    }
}

